var e=[{id:`L3_1`,type:`dialog`,speaker:`CANNON_SHARKS_NULL_NULL`,text:{KOREA:`흐아앙! 싫어! 또 불길한 빛을 내기 시작했어요!`,JPN:`ふええーん！　イヤです！　また不吉に光り出しました！`,ENG:`Waaah! Oh no! It started glowing red again!`,TWN:`吼！煩死了！他又開始發出討厭的光了！`},stage:{bg:`FRONTBAY_DECK_FOG`,slots:{L:null,C:{char_id:`CANNON_SHARKS_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`DAGGER_SHARKS_NULL_NULL`,text:{KOREA:`선장, 지금…!`,JPN:`船長、今……！`,ENG:`Captain, now...!`,TWN:`船長，現在…！`},stage:{bg:`FRONTBAY_DECK_FOG`,slots:{L:null,C:{char_id:`DAGGER_SHARKS_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`DRACO_NPC_SUMMER_NULL`,text:{KOREA:`지금이다! 발사!`,JPN:`今だ！　発射！`,ENG:`Now! FIRE!!`,TWN:`就是現在！開火！`},stage:{bg:`FRONTBAY_DECK_FOG`,slots:{L:null,C:{char_id:`DRACO_NPC_SUMMER_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`HUNTER_FRONTBAY_NULL_SEVERAL`,text:{KOREA:`신호가 떨어졌다! 쏴라!`,JPN:`合図が出たぞ！　撃て！`,ENG:`That's the signal! FIRE!`,TWN:`訊號來了！射擊！`},stage:{bg:`FRONTBAY_DECK_FOG`,slots:{L:{char_id:`HUNTER_FRONTBAY_NULL_SEVERAL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:`PIRATE_FRONTBAY_NULL_SEVERAL`,text:{KOREA:`갈겨! 갈기라고!`,JPN:`撃て！　撃てって！`,ENG:`Unload everything you've got! Keep firing!`,TWN:`開火！連續射擊！`},stage:{bg:`FRONTBAY_DECK_FOG`,slots:{L:{char_id:`HUNTER_FRONTBAY_NULL_SEVERAL`,face:`UNIT_IDLE`},C:null,R:{char_id:`PIRATE_FRONTBAY_NULL_SEVERAL`,face:`UNIT_SERIOUS`}}}},{id:`L18_1`,type:`dialog`,speaker:`CANNON_SHARKS_NULL_NULL`,text:{KOREA:`꺄아! 우리 배를 내려친다…!`,JPN:`きゃあ！　私たちの船を打ち落とす気です……！`,ENG:`Kyaah! It's about to slam our ship...!`,TWN:`哎呀！他擊中我們的船了…！`},stage:{bg:`FRONTBAY_DECK_FOG`,slots:{L:null,C:{char_id:`CANNON_SHARKS_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`CANNON_SHARKS_NULL_NULL`,text:{KOREA:`…가 아니라, 쓰러진 거네요?`,JPN:`……じゃなくて、倒れましたね？`,ENG:`...Oh, never mind. We defeated it.`,TWN:`…沒有欸？結果倒的是他？`},stage:{bg:`FRONTBAY_DECK_FOG`,slots:{L:null,C:{char_id:`CANNON_SHARKS_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`DAGGER_SHARKS_NULL_NULL`,text:{KOREA:`도망친 게 아니라… 쓰러뜨렸다고?`,JPN:`逃げたんじゃなくて……倒した？`,ENG:`It didn't run... and we defeated it?`,TWN:`他不是逃跑…而是真的倒下了？`},stage:{bg:`FRONTBAY_DECK_FOG`,slots:{L:null,C:{char_id:`DAGGER_SHARKS_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`HUNTER_FRONTBAY_NULL_SEVERAL`,text:{KOREA:`…안개가 걷혔어. 성공이군.`,JPN:`……霧が晴れた。成功だな。`,ENG:`...The fog's lifting. We did it.`,TWN:`……霧散去了，我們成功了。`},stage:{bg:`FRONTBAY_DECK`,slots:{L:{char_id:`HUNTER_FRONTBAY_NULL_SEVERAL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L25_1`,type:`dialog`,speaker:`HUNTER_FRONTBAY_NULL_SEVERAL2`,text:{KOREA:`해냈다! 우리가 크라켄을 잡았어!`,JPN:`やった！　俺たちがクラーケンを仕留めたぞ！`,ENG:`WE DID IT! We killed Kraken!`,TWN:`成功了！我們逮到克拉肯了！`},stage:{bg:`FRONTBAY_DECK`,slots:{L:{char_id:`HUNTER_FRONTBAY_NULL_SEVERAL`,face:`UNIT_IDLE`},C:null,R:{char_id:`HUNTER_FRONTBAY_NULL_SEVERAL2`,face:`UNIT_IDLE`}}}},{id:`L27_1`,type:`dialog`,speaker:`PIRATE_FRONTBAY_NULL_SEVERAL`,text:{KOREA:`크헤헤, 쌤통이다! 망할 괴물 놈!`,JPN:`クヘヘ、ざまあみろ！　クソ化け物め！`,ENG:`Kehehe! Eat lead, you monster!`,TWN:`哈哈哈，活該！這該死的怪物！`},stage:{bg:`FRONTBAY_DECK`,slots:{L:null,C:null,R:{char_id:`PIRATE_FRONTBAY_NULL_SEVERAL`,face:`UNIT_PRIDE`}}}},{id:`L28_1`,type:`dialog`,speaker:`PIRATE_FRONTBAY_NULL_SEVERAL2`,text:{KOREA:`어이! 믿고 있었다고, 드라코 선장!`,JPN:`おい！　信じていたぞ、ドラコ船長！`,ENG:`Captain Dracasia! I knew I could count on you!`,TWN:`喂！我就知道你行的，德拉克船長！`},stage:{bg:`FRONTBAY_DECK`,slots:{L:{char_id:`PIRATE_FRONTBAY_NULL_SEVERAL2`,face:`UNIT_LAUGH`},C:null,R:{char_id:`PIRATE_FRONTBAY_NULL_SEVERAL`,face:`UNIT_PRIDE`}}}},{id:`L31_1`,type:`dialog`,speaker:`DRACO_NPC_SUMMER_NULL`,text:{KOREA:`캬하핫- 당연하지!`,JPN:`キャハハッ～当たり前だろ！`,ENG:`Kya hah hah! Of course!`,TWN:`哇哈哈哈，那還用說！`},stage:{bg:`FRONTBAY_DECK`,slots:{L:null,C:{char_id:`DRACO_NPC_SUMMER_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L32_1`,type:`dialog`,speaker:`CANNON_SHARKS_NULL_NULL`,text:{KOREA:`뭐야. 생각보다 별거 아닌데요?`,JPN:`なんだ。思ったより大したことなかったですね。`,ENG:`Huh? That was kinda anticlimactic, no?`,TWN:`什麼嘛，他也沒那麼強嘛？`},stage:{bg:`FRONTBAY_DECK`,slots:{L:null,C:{char_id:`CANNON_SHARKS_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L33_1`,type:`dialog`,speaker:`CANNON_SHARKS_NULL_NULL`,text:{KOREA:`이런 게 무서워서 20년 동안이나 심해역을 피해다녔다니, 어른들도 정말 겁쟁이라니까요.`,JPN:`こんなものが怖くて20年も深海域を避けていたなんて、大人も本当に臆病者ですわ。`,ENG:`We avoided the deep sea area for 20 years because we were scared of this? Adults are such cowards, aren't they?`,TWN:`就因為害怕他，二十年來一直避開深海域的大人真是膽小鬼。`},stage:{bg:`FRONTBAY_DECK`,slots:{L:null,C:{char_id:`CANNON_SHARKS_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L36_1`,type:`dialog`,speaker:`DAGGER_SHARKS_NULL_NULL`,text:{KOREA:`너 방금 전까지 애처럼 울고 있었잖아?`,JPN:`あなた、さっきまで子どものように泣いてただろう。`,ENG:`Weren't you bawling your eyes out just now?`,TWN:`你剛才不是還哭得像個孩子嗎？`},stage:{bg:`FRONTBAY_DECK`,slots:{L:{char_id:`DAGGER_SHARKS_NULL_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`CANNON_SHARKS_NULL_NULL`,face:`UNIT_LAUGH`}}}}];export{e as default};